// ─────────────────────────────────────────
// Window-based feature extraction
// Match exactly how training data was collected
// Window size: 30 seconds
// ─────────────────────────────────────────

var WINDOW_SIZE = 30;  // seconds

// Get device identity
var deviceId = msg.payload.device_id;
if (!deviceId) return null;

// Get or initialize device window
var window = context.get(deviceId) || {
    messages   : [],
    windowStart: Date.now()
};

// Add current message to window
window.messages.push({
    timestamp    : Date.now() / 1000,  // seconds
    temperature  : msg.payload.temperature,
    humidity     : msg.payload.humidity,
    payload_size : msg.payload.payload_size,
    topic_depth  : msg.topic.split("/").length
});

// Check if window is complete
var windowAge = (Date.now() - window.windowStart) / 1000;

if (windowAge < WINDOW_SIZE) {
    // Window not complete yet — save and wait
    context.set(deviceId, window);
    return null;  // don't send anything to Flask yet
}

// ─────────────────────────────────────────
// Window complete — compute features
// ─────────────────────────────────────────
var messages = window.messages;
var n        = messages.length;

if (n < 2) {
    // Not enough messages — reset and wait
    context.set(deviceId, {
        messages   : [],
        windowStart: Date.now()
    });
    return null;
}

// msg_count
var msg_count = n;

// mean_interval and std_interval
var timestamps = messages.map(function(m) { return m.timestamp; });
var intervals  = [];
for (var i = 1; i < timestamps.length; i++) {
    intervals.push(timestamps[i] - timestamps[i-1]);
}
var mean_interval = intervals.reduce(function(a,b){ return a+b; }, 0) / intervals.length;
var variance      = intervals.reduce(function(a,b){ 
    return a + Math.pow(b - mean_interval, 2); 
}, 0) / intervals.length;
var std_interval  = Math.sqrt(variance);

// mean_payload_size
var sizes            = messages.map(function(m){ return m.payload_size; });
var mean_payload_size = sizes.reduce(function(a,b){ return a+b; }, 0) / n;

// mean_temp and std_temp
var temps     = messages.map(function(m){ return m.temperature; });
var mean_temp = temps.reduce(function(a,b){ return a+b; }, 0) / n;
var temp_var  = temps.reduce(function(a,b){ 
    return a + Math.pow(b - mean_temp, 2); 
}, 0) / n;
var std_temp  = Math.sqrt(temp_var);

// mean_humidity and std_humidity
var hums          = messages.map(function(m){ return m.humidity; });
var mean_humidity = hums.reduce(function(a,b){ return a+b; }, 0) / n;
var hum_var       = hums.reduce(function(a,b){ 
    return a + Math.pow(b - mean_humidity, 2); 
}, 0) / n;
var std_humidity  = Math.sqrt(hum_var);

// out_of_range_ratio
var out_of_range = messages.filter(function(m){
    return m.temperature < 10 || m.temperature > 40 ||
           m.humidity < 20    || m.humidity > 95;
}).length;
var out_of_range_ratio = out_of_range / n;

// topic_depth
var topic_depth = messages[0].topic_depth;

// ─────────────────────────────────────────
// Build feature object for Flask
// ─────────────────────────────────────────
var features = {
    device_id           : deviceId,
    msg_count           : msg_count,
    mean_interval       : Math.round(mean_interval   * 10000) / 10000,
    std_interval        : Math.round(std_interval    * 10000) / 10000,
    mean_payload_size   : Math.round(mean_payload_size * 100) / 100,
    mean_temp           : Math.round(mean_temp       * 100)   / 100,
    std_temp            : Math.round(std_temp        * 10000) / 10000,
    mean_humidity       : Math.round(mean_humidity   * 100)   / 100,
    std_humidity        : Math.round(std_humidity    * 10000) / 10000,
    out_of_range_ratio  : Math.round(out_of_range_ratio * 10000) / 10000,
    topic_depth         : topic_depth
};

// Save original payload for storage later
msg.originalPayload = msg.payload;
msg.deviceId        = deviceId;
msg.features        = features;
msg.payload         = features;

// Reset window for next 30-second period
context.set(deviceId, {
    messages   : [],
    windowStart: Date.now()
});

return msg;
